parameters.jsonBody:
={
  "timeline": {
    "soundtrack": {
      "src": "{{ $('6. Upload Audio (file.io)').item.json.link }}",
      "effect": "fadeOut"
    },
    "tracks": [
      {
        "clips": [
          {{  
            $('10. Aggregate All Scenes').item.json.scene_assets.map((scene, i) => JSON.stringify({
              "asset": {
                "type": "image",
                "src": scene.image_url
              },
              "start": $('10. Aggregate All Scenes').item.json.scene_assets.slice(0, i).reduce((sum, s) => sum + (s.duration_seconds || 8), 0),
              "length": scene.duration_seconds || 8,
              "effect": "zoomIn",
              "transition": {
                "in": "fade",
                "out": "fade"
              },
              "fit": "cover"
            })).join(',\n          ')
          }}
        ]
      },
      {
        "clips": [
          {
            "asset": {
              "type": "title",
              "text": {{ JSON.stringify($('2. Set Input Parameters').item.json.title) }},
              "style": "minimal",
              "size": "medium"
            },
            "start": 0,
            "length": 5,
            "transition": {
              "in": "fade",
              "out": "fade"
            }
          }
        ]
      }
    ]
  },
  "output": {
    "format": "mp4",
    "resolution": "hd",
    "aspectRatio": "16:9",
    "fps": 30
  }
}

